var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`오늘처럼 이렇게 기분이 고조되어본 것은 정말 오랜만입니다.`,JPN:`こんなにテンションが上がるのは実に久しぶりです。`,ENG:`It's been a while since the last time I was filled with so much emotion.`,TWN:`好久沒有像今天這樣振奮了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`평소였다면 폴짝 뛰어다니며 제 기분을 표출했을 텐데, 아쉽습니다.`,JPN:`いつもならピョンピョン跳びはねて気持ちを表すことができたのですが、残念です。`,ENG:`I would hop around with joy,`,TWN:`本來，我會跳來跳去來表達我的感受，真可惜。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`지금 같은 몸으로 그런 짓을 했다간 지반이 무너져 내릴 지도 모르는 일이지요.`,JPN:`このボディでそんなことをしたら、地盤崩壊を引き起こしかねませんからね。`,ENG:`but doing so in my current physical status could compromise the soil around me.`,TWN:`用現在這副身體這麼做的話，說不定整個地基都會垮掉。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`대신 그 제안은 전투 실적을 높임으로서 보답하도록 하겠습니다.`,JPN:`その提案には、より優れた戦闘実績を挙げることで報いたいと思います。`,ENG:`In return for your proposal, I will do my best to operate at the best efficiency during battle.`,TWN:`那我就以提高戰鬥業績，來報答您的這份提議吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`......앗.`,JPN:`……あっ。`,ENG:`Ah, no.`,TWN:`……啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`방금 발언은 철회시켜주세요.`,JPN:`今の発言は取り消させてください。`,ENG:`I'd like to withdraw my last comment.`,TWN:`請允許我撤回剛才的發言。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`저는 이 제안을 받기 전에도 항상 최선을 다하고 있었습니다.`,JPN:`私はこの提案をいただく前から、常に最善を尽くしていました。`,ENG:`I've always done my best. My performance has nothing to do with your kind offer.`,TWN:`收到這份提議之前，我就一直在全力以赴。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MACHINEGUN_ADMIN_NULL_NULL`,text:{KOREA:`계산절차를 거치지 않고 무책임한 소릴 해버려서 죄송합니다.`,JPN:`計算もせずに無責任な発言をしてしまい、申し訳ありませんでした。`,ENG:`Forgive me for the irresponsible, unprocessed remark.`,TWN:`未經運算流程，就說出這麼不負責任的話，我感到非常抱歉。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MACHINEGUN_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};